let oldKeywords = new Set([]);
if ($('Aggregate').first().json.data) {
 oldKeywords = new Set($('Aggregate').first().json.data
  .filter(item => item.Target == $('Get targets').first().json.Domain)
  .map(item => item.Keyword));
}

let diff = null;

if (oldKeywords.size) {
  let newKeywords = [];
  if ($('Merge "items" with last response').first().json.items) {
   newKeywords = $('Merge "items" with last response').first().json.items
    .map(item => item.keyword_data.keyword);
  }

  diff = newKeywords.filter(x => !oldKeywords.has(x));
}

return [
  {
    json: {
      diff
    }
  }
];
